const WeatherCard = ({
  city,
  icon,
  temperature,
  feelsLike,
  condition,
  wind,
  humidity,
  aqi
}) => {

  // ✅ STEP 1: extract AQI safely
  const rawAQI =
    aqi?.["us-epa-index"] ??
    aqi?.air_quality?.["us-epa-index"];

  // convert to number
  const aqiValue = Number(rawAQI);

  const hasAQI = Number.isFinite(aqiValue);

  // ✅ label
  const getAQILabel = (value) => {
    if (value === 1) return "Good";
    if (value === 2) return "Moderate";
    if (value === 3) return "Unhealthy (Sensitive)";
    if (value === 4) return "Unhealthy";
    if (value === 5) return "Very Unhealthy";
    if (value === 6) return "Hazardous";
    return "Unknown";
  };

  // ✅ color
  const getAQIColor = (value) => {
    if (value === 1) return "#00e400";
    if (value === 2) return "#ffff00";
    if (value === 3) return "#ff7e00";
    if (value === 4) return "#ff0000";
    if (value === 5) return "#8f3f97";
    if (value === 6) return "#7e0023";
    return "#ccc";
  };

  return (
    <div className="card">
      <h2>{city}</h2>

      <img src={icon} alt="weather icon" />

      <p>Temperature: {temperature}</p>
      <p>Feels Like: {feelsLike}</p>
      <p>Condition: {condition}</p>
      <p>Wind: {wind}</p>
      <p>Humidity: {humidity}</p>

      {/* 🔥 AQI BOX */}
      <div
        style={{
          backgroundColor: hasAQI ? getAQIColor(aqiValue) : "#ccc",
          padding: "10px",
          borderRadius: "8px",
          marginTop: "10px",
          fontWeight: "bold"
        }}
      >
        AQI: {hasAQI ? aqiValue : "N/A"} — {hasAQI ? getAQILabel(aqiValue) : "Unknown"}
      </div>
    </div>
  );
};

export default WeatherCard;
